# tests/test_flags.py
import pytest
from unittest.mock import patch, MagicMock
from app.pipeline import run_pipeline

@pytest.fixture
def flag_off(monkeypatch):
    """Fixture that sets all flags to stable/off defaults."""
    def mock_get(key, default=None):
        defaults = {
            'new_rag_pipeline': False,
            'system_prompt_variant': 'v1',
            'canary_pct': 0.0,
            'max_tokens_override': 1024,
        }
        return defaults.get(key, default)
    monkeypatch.setattr('app.pipeline.flag_store.get', mock_get)

@pytest.fixture
def flag_on(monkeypatch):
    """Fixture that enables all experimental flags."""
    def mock_get(key, default=None):
        overrides = {
            'new_rag_pipeline': True,
            'system_prompt_variant': 'v2',
            'canary_pct': 1.0,
            'max_tokens_override': 512,
        }
        return overrides.get(key, default)
    monkeypatch.setattr('app.pipeline.flag_store.get', mock_get)

@patch('app.rag.build_context_v1')
@patch('app.rag.build_context_v2')
def test_flag_off_uses_v1_rag(mock_v2, mock_v1, flag_off):
    run_pipeline('user1', 'sess1', 'hello')
    mock_v1.assert_called_once()
    mock_v2.assert_not_called()

@patch('app.rag.build_context_v1')
@patch('app.rag.build_context_v2')
def test_flag_on_uses_v2_rag(mock_v2, mock_v1, flag_on):
    run_pipeline('user1', 'sess1', 'hello')
    mock_v2.assert_called_once()
    mock_v1.assert_not_called()
